challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The UPF is the source of data plane packet loss, causing a high packet loss ratio reported by RTPEngine and triggering the `core.upf.activity_during_calls_collapsed` event.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "Check UPF in/out data plane packet rates for symmetry over a 60-second window. This checks for discrepancies between packets received by the UPF and packets it forwards.",
          "expected_if_hypothesis_holds": "The probe returns asymmetric packet rates for the UPF (e.g. `upf.gtp_indatapktn3upf_per_ue` and `upf.gtp_outdatapktn3upf_per_ue` are imbalanced), indicating a discrepancy in packet handling.",
          "falsifying_observation": "The probe returns symmetric packet rates for the UPF (e.g., `upf.gtp_indatapktn3upf_per_ue` and `upf.gtp_outdatapktn3upf_per_ue` are roughly equal during active calls), suggesting it is forwarding packets as expected.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "Check RTPEngine's reported packet loss ratio over the same 60-second window to confirm the downstream impact.",
          "expected_if_hypothesis_holds": "The `ims.rtpengine.loss_ratio` metric is significantly greater than 0, confirming the presence of high packet loss in the media plane as observed by RTPEngine.",
          "falsifying_observation": "The `ims.rtpengine.loss_ratio` metric is at or near 0. This would indicate a healthy media plane from RTPEngine's perspective, which contradicts the hypothesis's stated consequence.",
          "conflates_with": []
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "Check for any internally-generated errors within RTPEngine over the same 60-second window to rule out RTPEngine as the primary cause.",
          "expected_if_hypothesis_holds": "The `ims.rtpengine.errors_per_second` metric is 0. This suggests the high loss ratio is from an upstream source and not from RTPEngine's own processing.",
          "falsifying_observation": "The `ims.rtpengine.errors_per_second` metric is greater than 0, suggesting that RTPEngine itself is encountering errors and could be the source of the media plane issues, which would falsify the hypothesis about UPF being the source.",
          "conflates_with": []
        }
      ],
      "notes": "The hypothesis concerns a failure in the VoNR data plane. The relevant flow is `vonr_call_setup`, particularly step 12 ('RTP media - voice call active'), which traverses the UPF."
    }
  ]
}

